import{_ as h,r as i,o as c,c as u,a as t,d as l,w as n,f as o,b as e,e as s}from"./app-711694f0.js";const _="/images/hobbies/rhythm_games/osu_best.jpg",p="/images/hobbies/rhythm_games/phigros_best.jpg",g="/images/hobbies/rhythm_games/arcaea_best.jpg",m="/images/hobbies/rhythm_games/sbgaaru.png",f={},y=t("h1",{id:"音游",tabindex:"-1"},[t("a",{class:"header-anchor",href:"#音游","aria-hidden":"true"},"#"),e(" 音游")],-1),x=t("p",null,"至今我只打过移动端音游。本篇不含任何街机元素。",-1),b={class:"table-of-contents"},k=s('<h2 id="回忆" tabindex="-1"><a class="header-anchor" href="#回忆" aria-hidden="true">#</a> 回忆</h2><p>小时候有打过节奏大师，很菜，平常管控也很严，拿不到手机。因此打的时长可以忽略不计。</p><p>真正开始打音游是在高二吧（20200614），在别人的推荐下开始玩 phigros。此时也是偶尔打打<span class="heimu" title="你知道的太多了">基本不打</span>。我当时用的设备是华为荣耀 9，延迟离谱外加断触严重，但我还是喜欢上了音游。</p><p>顺便说一句，我当时还有试着接触过喵赛克（玩两小时卸了，没有任何记录），project fx（最早记录是 20200722）等音游，不过并不持久。后来手机空间快用完了（64G）就卸了。</p><p>我的第一个音游视频是 2020 年 11 月发布的（已经是高三上了），当时全连了 FULI AUTO SHOOTER。此后又发了一堆视频。</p><p>我接触（并且持续玩至今）的第二个音游是 Arcaea。日记中最早出现<code>arc</code>的时间是 20201217。开始时很菜，后来才慢慢发现 arcaea 的魅力。</p><p>应该是在 2020 年下半年沉迷音游的。音游水平突飞猛进。（要是高考成绩也能突飞猛进就好了）高考完后还入坑了プロセカ，大学刚开学入坑了 osu，（大一下）买了平板后下载了 lanota，等等。</p><h2 id="总体现况" tabindex="-1"><a class="header-anchor" href="#总体现况" aria-hidden="true">#</a> 总体现况</h2><p>我是音押人，这里的音押指的是敲键盘或屏幕时的声音跟音乐声重合；同时也因为小米平板 5 的屏幕延迟数据稀烂的影响，我玩音游的延迟设置非常怪。我没法快速适应其他音游人的设备，别人也同理。<span class="heimu" title="你知道的太多了">（我们之间已经隔了一层可悲的厚障壁了）</span>我接触一个新音游要做的第一件事并不是新手教程而是不断尝试调延迟。</p><p>音游调整延迟大多是听重音是否重合，对我来说<strong>p 用没有</strong>。因为重音与触屏延迟没有任何关系，我的延迟根本无法调整！下面也会列举各音游调延迟的人性化程度分数<span class="heimu" title="你知道的太多了">包含了我的无尽怨念</span>。</p><p>本人所有触屏设备音游均关闭打击音效。</p>',11),w=s('<table><thead><tr><th style="text-align:center;">音游名</th><th style="text-align:center;">游玩时长(%,初期数据)</th><th style="text-align:center;">延迟</th><th style="text-align:center;">谱面速度</th><th style="text-align:center;">延迟人性化程度得分</th></tr></thead><tbody><tr><td style="text-align:center;">osu</td><td style="text-align:center;">81</td><td style="text-align:center;"><text style="color:red;">将星X15内置声卡: -86ms<br>GS02声卡 -41ms</text></td><td style="text-align:center;">30</td><td style="text-align:center;">0</td></tr><tr><td style="text-align:center;">osu!lazer</td><td style="text-align:center;">-</td><td style="text-align:center;"><text style="color:red;">-107ms - -94ms</text></td><td style="text-align:center;">25</td><td style="text-align:center;">4</td></tr><tr><td style="text-align:center;">phigros(latest)</td><td style="text-align:center;">10</td><td style="text-align:center;"><text style="color:blue;">+100ms</text></td><td style="text-align:center;">-</td><td style="text-align:center;">1</td></tr><tr><td style="text-align:center;">arcaea</td><td style="text-align:center;">7</td><td style="text-align:center;"><text style="color:blue;">75</text></td><td style="text-align:center;">5</td><td style="text-align:center;">5</td></tr><tr><td style="text-align:center;">KALPA</td><td style="text-align:center;">&lt;1</td><td style="text-align:center;"><text style="color:red;">-148ms</text></td><td style="text-align:center;">6.5</td><td style="text-align:center;">5</td></tr><tr><td style="text-align:center;">lanota</td><td style="text-align:center;">&lt;0.5</td><td style="text-align:center;"><text style="color:blue;">+12</text></td><td style="text-align:center;">7.0</td><td style="text-align:center;">0</td></tr><tr><td style="text-align:center;">Dynamix</td><td style="text-align:center;">&lt;0.1</td><td style="text-align:center;"><text style="color:red;">-0.12</text></td><td style="text-align:center;">1.2</td><td style="text-align:center;">2</td></tr><tr><td style="text-align:center;">Malody</td><td style="text-align:center;">&lt;0.1</td><td style="text-align:center;"><text style="color:red;">-164;-4?</text></td><td style="text-align:center;">10</td><td style="text-align:center;">10</td></tr><tr><td style="text-align:center;">phigros(2.1.4)</td><td style="text-align:center;">&lt;0.05</td><td style="text-align:center;"><text style="color:blue;">+75ms</text></td><td style="text-align:center;">-</td><td style="text-align:center;">1</td></tr><tr><td style="text-align:center;">phigros(1.6.5)</td><td style="text-align:center;">&lt;0.05</td><td style="text-align:center;">+105ms</td><td style="text-align:center;">-</td><td style="text-align:center;">1</td></tr><tr><td style="text-align:center;">phigros(1.4.1)</td><td style="text-align:center;">&lt;0.04</td><td style="text-align:center;">+120ms</td><td style="text-align:center;">-</td><td style="text-align:center;">1</td></tr><tr><td style="text-align:center;">プロセカ</td><td style="text-align:center;">&lt;0.01</td><td style="text-align:center;"><text style="color:red;">-2</text></td><td style="text-align:center;">10.7</td><td style="text-align:center;">2</td></tr></tbody></table>',1),S=t("p",null,[t("em",null,[e("（注：延迟中的颜色含义为延迟调整方法：纯音押打歌后，"),t("text",{style:{color:"red"}},"late 过多，向负方向调整，early 过多，向正方向调整；"),e(),t("text",{style:{color:"blue"}},"late 过多，向正方向调整，early 过多，向负方向调整。"),e("）")])],-1),v=t("p",null,[t("strong",null,"游玩时长变化情况：")],-1),A=t("iframe",{frameborder:"no",src:"/charts/rhythm_games_time_percentage.html",width:"100%",height:"280",loading:"lazy"},null,-1),E=s('<h2 id="观点" tabindex="-1"><a class="header-anchor" href="#观点" aria-hidden="true">#</a> 观点</h2><ul><li>OSU 敲键盘的快感是敲平板无法带来的：平板用力会敲坏，而且越级空有力气还不一定能敲到键上。而 OSU 很适合发泄情绪。x</li><li>我很讨厌在面条上写变速的谱师。非常讨厌。</li></ul><h2 id="osu" tabindex="-1"><a class="header-anchor" href="#osu" aria-hidden="true">#</a> OSU</h2><div class="subtitle">——空を超えるために、頑張らなくちゃいけないんだよ！</div><blockquote><p>20230514 - 20230629 退坑</p></blockquote>',5),O={href:"https://osu.ppy.sh/users/25751103",target:"_blank",rel:"noopener noreferrer"},R=t("h3",{id:"我的记录",tabindex:"-1"},[t("a",{class:"header-anchor",href:"#我的记录","aria-hidden":"true"},"#"),e(" 我的记录")],-1),z=t("ul",null,[t("li",null,[e("我的 o!m 健身按键数 "),t("s",null,"（众所周知 osu 是健身游戏）")])],-1),N=t("iframe",{frameborder:"no",src:"/charts/keysnum.html",width:"100%",height:"300",loading:"lazy"},null,-1),j=t("ul",null,[t("li",null,"叠（Jack）：β, ex-4")],-1),M=t("iframe",{frameborder:"no",src:"/charts/reform_jack.html",width:"100%",height:"280",loading:"lazy"},null,-1),B=t("iframe",{frameborder:"no",src:"/charts/malody_jack.html",width:"100%",height:"280",loading:"lazy"},null,-1),C=t("ul",null,[t("li",null,[e("技（Tech）：β, ex-4 "),t("ul",null,[t("li",null,"本人最擅长技。尤其是偏叠的技。")])])],-1),P=t("iframe",{frameborder:"no",src:"/charts/reform_tech.html",width:"100%",height:"280",loading:"lazy"},null,-1),T=t("iframe",{frameborder:"no",src:"/charts/malody_tech.html",width:"100%",height:"280",loading:"lazy"},null,-1),G=t("ul",null,[t("li",null,[e("乱（Speed）：10, ex-2 "),t("ul",null,[t("li",null,"严重偏科。")])])],-1),L=t("iframe",{frameborder:"no",src:"/charts/reform_speed.html",width:"100%",height:"280",loading:"lazy"},null,-1),U=t("iframe",{frameborder:"no",src:"/charts/malody_speed.html",width:"100%",height:"280",loading:"lazy"},null,-1),V=t("ul",null,[t("li",null,[e("切（Stamina / Stream）：β, ex-4 "),t("ul",null,[t("li",null,"耐力是限制切力的最重要因素。耐力不稳定，因此成绩不稳定。"),t("li",null,"非常痛恨无休切。Malody v3 段打得挺好，但 reform 段极为下手。")])])],-1),D=t("iframe",{frameborder:"no",src:"/charts/reform_stamina.html",width:"100%",height:"280",loading:"lazy"},null,-1),I=t("iframe",{frameborder:"no",src:"/charts/malody_stream.html",width:"100%",height:"280",loading:"lazy"},null,-1),q={class:"hint-container details"},K=t("summary",null,"一些解释说明",-1),F=t("li",null,"上为 reform 段位，下为 malody v3 段位；MR 等特殊 MOD 不显示。",-1),Y=t("li",null,"20221022?,20230309?,20230324?：由于 osu-kps（记录键数的软件）崩溃，导致键数只能取估计值。",-1),J=t("h3",{id:"说两句",tabindex:"-1"},[t("a",{class:"header-anchor",href:"#说两句","aria-hidden":"true"},"#"),e(" 说两句")],-1),Z={href:"https://mzh.moegirl.org.cn/Osu!",target:"_blank",rel:"noopener noreferrer"},H={href:"https://www.bilibili.com/read/mobile?id=11073476",target:"_blank",rel:"noopener noreferrer"},X=t("p",null,"Win11 更新到现在，对 osu 游玩体验没啥影响了，可以放心上。",-1),Q={class:"hint-container details"},W=t("summary",null,"我的经历",-1),$=t("p",null,"原本大学时看到音游群的同学在玩 osu，我也入坑了，想着练练 4k 可以提高我其他音游的成绩（多指力）。当时打了好久 osu 默认自带的那几首曲子，后来才知道怎么下载曲子...",-1),tt={class:"heimu",title:"你知道的太多了"},et={href:"https://store.steampowered.com/app/607260/McOsu/",target:"_blank",rel:"noopener noreferrer"},lt=s('<ul><li>为什么打 osu 最频繁呢？</li></ul><p>因为上限最高。 <strong>osu，本是逆天而行。</strong> <span class="heimu" title="你知道的太多了">（内卷而行</span> <s>虽然 Malody 同样具有高上限，但是固定 key 还是习惯敲键盘…</s><span class="heimu" title="你知道的太多了">明明最早接触的是触屏端 <a href="#%E8%A7%82%E7%82%B9">为什么会变成这样呢？</a></span></p><ul><li>其他想说的。</li></ul><p>我曾经历了一段时间的准度崩坏期（2022.06.28 前后），现在想来，应该是当时打段位过于急于求成了，无视准度打了很多超过我极限的曲子。为了救回准度付出了一定代价。所以，<strong>在逆天的路上，也别忘了去欣赏沿途的风景。</strong> 还有，<strong>OSU 如逆水行舟，不进则退</strong>，72h 内需要有完全热手的时间，否则实力就会开始退步。对我而言，4 天不打 OSU，就需要约 20w 键的复健才能恢复原先水平。</p>',4),rt=s('<h4 id="osu-缺陷" tabindex="-1"><a class="header-anchor" href="#osu-缺陷" aria-hidden="true">#</a> OSU 缺陷</h4><p>打了两年，感觉 OSU 存在着一些问题。我直接开始暴论。</p><ul><li>pp 设计不合理。同水平段的 6,7k 玩家比 4k 玩家的 pp 和排名要高。</li><li>倍速 mod 只有 0.75x 和 1.5x 两个可选，而很多高难歌曲甚至需要 0.05x 的间距划分。</li><li>设计缺陷，windows 下声道合成的延迟极高。原生不支持 ASIO。</li><li>设计缺陷，只能调打击 offset，但是音游能调整的 offset 实际上应该要有两个：<em>打击</em>，<em>音乐</em>，<em>谱面</em> 三选二。 <ul><li>只能调一个 offset 的结果就是音押和目押没法兼顾。</li></ul></li><li>官方态度，stable 玩家不被支持，赶人去 lazer。</li><li>而 lazer 很难用：安装时无法选择安装目录；谱面文件夹不公开；迁移后皮肤高度出现不适配。（据说）还有卡顿问题。</li><li>服务器缺陷：mania 下载歌曲时不能按 key 数筛选。而不同 key 数的 mania 基本相当于两个游戏。</li></ul><p>我也被坑了几次<sup class="footnote-ref"><a href="#footnote1">[1]</a><a class="footnote-anchor" id="footnote-ref1"></a></sup>。</p><h3 id="设置" tabindex="-1"><a class="header-anchor" href="#设置" aria-hidden="true">#</a> 设置</h3>',5),nt={href:"https://github.com/Evisolpxe/OsuCNwiki/blob/master/jin-jie-zhi-lu/xu-yao-yong-dao-de-ruan-jian-zhi-shi.md",target:"_blank",rel:"noopener noreferrer"},at=t("h4",{id:"调整延迟",tabindex:"-1"},[t("a",{class:"header-anchor",href:"#调整延迟","aria-hidden":"true"},"#"),e(" 调整延迟")],-1),st=t("p",null,"offset 对个人手感，后续进步与习惯养成极为重要。但是调整 offset 是个漫长而痛苦的过程（20230502-03，16w 键才调好）。",-1),ot=t("p",null,[e("我个人习惯音乐声与键盘声同步，需要同时考虑键盘输入延迟和音乐延迟。键盘延迟一般在 1ms 左右，关系不大，而音乐延迟极难调整。官方对音，录制波形，都是调整 key 音的手段，对音乐无能为力。摸索了非常久才得出一个比较好的方法："),t("strong",null,"将分数计（看准度的那个条）调大，开 NF 打节奏强的 rank 图"),e("，打一段调整一下。rank 图也并非没有 offset 问题，需要多打不同谱面，不断调整。")],-1),it=t("h3",{id:"键盘参数",tabindex:"-1"},[t("a",{class:"header-anchor",href:"#键盘参数","aria-hidden":"true"},"#"),e(" 键盘参数")],-1),dt=s('<table><thead><tr><th style="text-align:center;">轴体</th><th style="text-align:center;">使用时间区间</th><th style="text-align:center;">优点</th><th style="text-align:center;">缺点</th></tr></thead><tbody><tr><td style="text-align:center;">光轴</td><td style="text-align:center;">2020-20220530</td><td style="text-align:center;">便宜<br>延迟低<br>耐操</td><td style="text-align:center;">巨吵无比<br>触发压力大<br>无法换轴</td></tr><tr><td style="text-align:center;">AJAZZ红轴</td><td style="text-align:center;">20220607-20220609</td><td style="text-align:center;">手感不错<br>静音</td><td style="text-align:center;">-</td></tr><tr><td style="text-align:center;">RK红轴</td><td style="text-align:center;">20220611-20220614</td><td style="text-align:center;">触发压力小</td><td style="text-align:center;">触发键程大</td></tr><tr><td style="text-align:center;"><text style="color:blue;">快银轴</text></td><td style="text-align:center;">20220614-至今</td><td style="text-align:center;">快，触发键程小</td><td style="text-align:center;">触发压力稍大</td></tr><tr><td style="text-align:center;">金粉轴v2</td><td style="text-align:center;">20220624-20220625</td><td style="text-align:center;">触发压力小</td><td style="text-align:center;">触发键程大，延迟高</td></tr></tbody></table><p>大一用了一整年的地摊货键盘，光轴，咸鱼 40 的网吧淘汰品。延迟很低，可以随便泡水不会坏——但是巨 tm 吵，舍友震怒；而且触发压力大，打得很累。</p><p>放假回家后用过了 AJAZZ 红轴，手感还行，可惜因为套件模具不喜欢，退掉了。第三次换的是 RK 红轴，打字舒服但是打 osu 不行：因为触发键程问题，轻按与重按的触发延迟是不一样的，导致我爆发段和正常段准度总会死一个。<span class="heimu" title="你知道的太多了">现在想想，当时是换键盘的延迟适应期，准度差挺正常的，不该甩锅</span></p><p>第四也就是现在用的，朋友送我几个 ttc 快银轴，试了试，手感挺不错的。不过还有一些缺点：克数稍微大了点(45g)，打久了累；声音也比较大。</p><p>第五，ttc 金粉 v2，跟第三个 RK 红轴很像，这里不多说（好像因为工艺原因延迟较大）。摸完五种轴我感觉应该已经有了一定的认知了，<strong>osu 不仅仅是耐力游戏，更是准度游戏，键程比压力更重要。</strong> 快银凭借导通行程 1.08+0.4/-0.2mm，总行程 3.4-0.4mm 获得第一。</p><p>在<a href="#%E5%85%B6%E4%BB%96%E6%8E%A8%E8%8D%90">键盘/轴推荐</a>这里再多 bb 两句。</p><h3 id="皮肤" tabindex="-1"><a class="header-anchor" href="#皮肤" aria-hidden="true">#</a> 皮肤</h3><p>大一一整年用的是蓝白钉皮，R Skin v3.1 (diamond) 的改版。可以在我的 B 站视频里找到。顺带一提，当时也是试了好多皮肤，发现其他皮肤都没什么手感，只有这套拥有超亮击打特效的蓝白钉皮很对我的胃口。<s>当然，猫猫也很好看！</s></p><p>然后地狱时刻（20220612）到了，我下载了一个别人的同名皮肤，并且覆盖掉了原皮肤。这种覆盖是不可逆的，无法恢复。同时我在当时下载皮肤的群里和网上疯狂找原皮肤。找不到了，销声匿迹了，找到的都是 R Skin 的原版或其他改版。这大概是我最痛苦的一个晚上。</p><p>第二天我几乎是死心了，开始了自己融合皮肤的过程，希望能融出像原来那种的蓝白钉皮。自己融了整整一天，也融不出什么手感好的皮肤。</p><p>然后在 20220613 晚上，放弃自己原本融的那个（absolute x v1），在朋友帮助下重新开始再融一个。基准皮肤选的是 R Skin v3.0 (Jakads&#39; New) LNCut，结果只需稍稍修改，就融出了 absolute x v2。手感还不错，能够足够逼近原来的皮肤了。</p>',11),ht={href:"https://osu.ppy.sh/community/forums/topics/1746341",target:"_blank",rel:"noopener noreferrer"},ct=t("h3",{id:"段位",tabindex:"-1"},[t("a",{class:"header-anchor",href:"#段位","aria-hidden":"true"},"#"),e(" 段位")],-1),ut=t("p",null,"叠和切主要考验手速和耐力；乱是节奏和读谱；技在这二者之间。",-1),_t=t("h4",{id:"_4k",tabindex:"-1"},[t("a",{class:"header-anchor",href:"#_4k","aria-hidden":"true"},"#"),e(" 4k")],-1),pt={href:"https://wwp.lanzout.com/iIUjo02rxm5a",target:"_blank",rel:"noopener noreferrer"},gt={href:"https://osu.ppy.sh/beatmapsets?q=malody%204k%20regular%20dan%20v3&s=any",target:"_blank",rel:"noopener noreferrer"},mt={href:"https://osu.ppy.sh/beatmapsets?q=malody%204k%20extra%20dan%20v3&s=any",target:"_blank",rel:"noopener noreferrer"},ft={href:"https://osu.ppy.sh/beatmapsets?q=4k%20ln%20dan&s=any",target:"_blank",rel:"noopener noreferrer"},yt={href:"https://www.bilibili.com/read/cv21330945",target:"_blank",rel:"noopener noreferrer"},xt={href:"https://www.bilibili.com/read/cv19532510",target:"_blank",rel:"noopener noreferrer"},bt=t("h4",{id:"_6k",tabindex:"-1"},[t("a",{class:"header-anchor",href:"#_6k","aria-hidden":"true"},"#"),e(" 6k")],-1),kt=t("p",null,[e("6k 对玩家与谱面把控极为严格。"),t("s",null,"（怎么会事呢？）"),e(" 请加入 QQ 群: 579602633 获取谱面与资讯。群内对成员活跃度有一定要求。")],-1),wt=t("h3",{id:"其他推荐",tabindex:"-1"},[t("a",{class:"header-anchor",href:"#其他推荐","aria-hidden":"true"},"#"),e(" 其他推荐")],-1),St=t("blockquote",null,[t("p",null,"由于我在家的房间采光极差，白天跟傍晚的光线差不多，而我用的 osu 皮肤是蓝白钉皮，非常刺眼，因此我使用这款护眼软件。osu 运行时会自动屏蔽 win10 的夜间模式，但 f.lux 可以无视这个屏蔽（win10 不稳定，win11 稳定），强制护眼，我还是觉得很舒服的。平时玩电脑也是常开的。")],-1),vt=t("li",null,[e("键盘/轴推荐：轴体以线性轴为佳;本人"),t("a",{href:"#%E9%94%AE%E7%9B%98%E5%8F%82%E6%95%B0"},"根据经验推荐 ttc 快银轴"),e("。 "),t("blockquote",null,[t("p",null,[e("随便找个你喜欢的热插拔轴的机械键盘，然后把 osu 键位的轴换成趁手的。这是最经济实惠的办法，没有必要整个键盘都是昂贵的轴。"),t("br"),e(),t("strong",null,"不要买低端达尔优键盘！"),e(" 摸过两个百元价位的，主控问题很大，四键同时按会阻塞，丢响应。真的垃圾。")])])],-1),At={href:"https://wwp.lanzout.com/ilX4V06l9yef",target:"_blank",rel:"noopener noreferrer"},Et=t("blockquote",null,[t("p",null,"按照 bp 列表下载会闪退。只能按 ranked 时间下载，且不可选择 key 数。但它已经是我用过的最好用的谱面下载器了。")],-1),Ot={href:"https://github.com/UnnamedOrange/osu-kps",target:"_blank",rel:"noopener noreferrer"},Rt={href:"https://github.com/lxl66566/osu-ColumnStart-adjustor",target:"_blank",rel:"noopener noreferrer"},zt={href:"https://wwp.lanzout.com/iuJPC06l9xje",target:"_blank",rel:"noopener noreferrer"},Nt=t("h3",{id:"最好成绩",tabindex:"-1"},[t("a",{class:"header-anchor",href:"#最好成绩","aria-hidden":"true"},"#"),e(" 最好成绩")],-1),jt={href:"https://www.bilibili.com/video/av661009839/",target:"_blank",rel:"noopener noreferrer"},Mt={href:"https://wwkh.lanzout.com/iGlrJ18lyudi",target:"_blank",rel:"noopener noreferrer"},Bt={href:"https://www.bilibili.com/video/BV1R8411A7Ye",target:"_blank",rel:"noopener noreferrer"},Ct={href:"https://www.bilibili.com/video/BV1vv4y1p7b1",target:"_blank",rel:"noopener noreferrer"},Pt=t("img",{src:_,alt:"malody v3 ex2 96.03%",loading:"lazy"},null,-1),Tt={href:"https://www.bilibili.com/video/BV1Ks4y1K77B/",target:"_blank",rel:"noopener noreferrer"},Gt=s('<h2 id="phigros" tabindex="-1"><a class="header-anchor" href="#phigros" aria-hidden="true">#</a> phigros</h2><p>目前处于瓶颈期/厌倦期：因 osu 打多了开始反感谱面演出；15 好听的能收的基本上收完了<span class="heimu" title="你知道的太多了">放屁</span>；16 能 ap 的 <em>（Lyrith -迷宮リリス-）</em> 懒得打，摆烂；16 想 ap 的 <em>（Stasis）</em> 还没解 5k 段。16 上位 <em>（igallta &amp; Rrhar&#39;il）</em> 根本不会打。</p><p>同时因为电脑端音游（OSU）打得多了，越来越不适应小米平板的极高延迟（100ms），让我更加不想碰它。<span class="heimu" title="你知道的太多了">给不能收歌的我再找个借口</span></p>',3),Lt=t("h3",{id:"数据转移",tabindex:"-1"},[t("a",{class:"header-anchor",href:"#数据转移","aria-hidden":"true"},"#"),e(" 数据转移")],-1),Ut=t("p",null,"同品牌手机可以用自带的换机工具转移。（例：小米换机）",-1),Vt={class:"hint-container details"},Dt=s("<summary>老方法失效，archived</summary><p>此处给出另一应用范围更广的 phigros 数据转移方法：</p><ol><li>移动设备打开 USB 调试并与电脑端连接。</li><li>备份：<code>adb backup -f NAME.ab -noapk -noshared -nosystem com.PigeonGames.Phigros</code><ul><li><code>NAME</code>最好包括游戏名、版本、备份时间等信息。</li></ul></li><li>恢复：<code>adb restore NAME.ab</code></li></ol>",3),It={href:"https://github.com/lxl66566/my-key-data/releases/tag/backup",target:"_blank",rel:"noopener noreferrer"},qt=s('<p>现在有在线存档了，请使用在线存档转移。而且能否下载到老版本也是个问题。</p><h3 id="最好成绩-1" tabindex="-1"><a class="header-anchor" href="#最好成绩-1" aria-hidden="true">#</a> 最好成绩</h3><p>15.9 all perfect</p><figure><img src="'+p+'" alt="15.9 all perfect" tabindex="0" loading="lazy"><figcaption>15.9 all perfect</figcaption></figure><h3 id="共存版" tabindex="-1"><a class="header-anchor" href="#共存版" aria-hidden="true">#</a> 共存版</h3>',5),Kt={href:"https://pan.baidu.com/s/1dRuoIVPCCgkbSxCyD-Z-IQ?pwd=2022",target:"_blank",rel:"noopener noreferrer"},Ft={href:"https://www.bilibili.com/video/BV1L44y15713",target:"_blank",rel:"noopener noreferrer"},Yt=t("h2",{id:"arcaea",tabindex:"-1"},[t("a",{class:"header-anchor",href:"#arcaea","aria-hidden":"true"},"#"),e(" Arcaea")],-1),Jt=s('<p>我在 arc 打歌基本只打好听的戳 xp 的曲子，这也导致了我在各曲子上的实力极度不均衡。</p><p>之前用手机打，后来买了 mipad5，平板大，接蛇确实好接。但是米板断触极为严重，属实傻逼。</p><h3 id="账号" tabindex="-1"><a class="header-anchor" href="#账号" aria-hidden="true">#</a> 账号</h3><p>本人账号（917042883）0 氪，很久没登录了。一直在借别人的号打。感谢 NitroYlide 和 Colinxu29 的支持。</p><h3 id="我的-xp" tabindex="-1"><a class="header-anchor" href="#我的-xp" aria-hidden="true">#</a> 我的 XP</h3><p>此处列出一些我觉得好听的曲子（Favorites 的一部分）。（排名按照 FTR 难度顺序）</p><p>&lt;=9: INTERNET OVERDOSE, Particle Arts, Alice&#39;s Suitcase, Equilibrium, Vindication</p><p>9+: 7thSense, amygdata, Defection, Far Away Light, Infinite Strife,, Lost Desire, Sulfur</p><p>10: Climax, cyanine, <code>Good bye, Merry-Go-Round</code>, GLORY : ROAD, Löschen, Oshama Scramble!, Pentiment, PRAGMATISM, Sheriruth, アリス・リデルに捧ぐ, 妖艶魔女 -trappola bewitching-</p>',9),Zt=t("p",null,"10+: #1f1e33, AMAZING MIGHTYYYY!!!!, Cyaegha, Halcyon, ouroboros -twin stroke of the end-, 烈華RESONANCE, Ringed Genesis, Singularity, Stasis, Tempestissimo, Testify, TEmPTaTiON, World Vanquisher",-1),Ht=s('<p>11: Aegleseeker, Grievous Lady, 最強STRONGER</p><h3 id="最好成绩-2" tabindex="-1"><a class="header-anchor" href="#最好成绩-2" aria-hidden="true">#</a> 最好成绩</h3><p>Sheriruth 10.1 pure memory</p><figure><img src="'+g+'" alt="Sheriruth 10.1 pure memory" tabindex="0" loading="lazy"><figcaption>Sheriruth 10.1 pure memory</figcaption></figure><h3 id="其他" tabindex="-1"><a class="header-anchor" href="#其他" aria-hidden="true">#</a> 其他</h3>',5),Xt={href:"https://www.mbrjun.cn/archives/443/",target:"_blank",rel:"noopener noreferrer"},Qt=t("code",null,"/data/data/moe.low.arc/shared_prefs/Cocos2dxPrefsFile.xml",-1),Wt=t("code",null,'<string name="fr_k">e71fbd09303b100e1e97b9acc8970bb4</string>',-1),$t=t("code",null,'<int name="fr_v" value="29997" />',-1),te={href:"https://t.me/GlowerHi_mods/24",target:"_blank",rel:"noopener noreferrer"},ee=s('<h2 id="pjsk" tabindex="-1"><a class="header-anchor" href="#pjsk" aria-hidden="true">#</a> pjsk</h2><p>20230715，我为我的 mipad5 解 bl 锁。由于需要清空数据，我复制出了我的引き継ぎ码并发给了我的 telegram 收藏夹。</p><p>机也刷完了，pjsk 也下回来了，我去 tg 找我的码时，震惊地发现——它没了。或许是梯子问题没发出去，或许是我误删了，反正它没了。</p><p>众所周知 tg 收藏夹无法恢复，而我好久没打 pjsk 了，账号信息基本上不记得。。因此没有任何一丝可能性能救回我的账号。<s>里面有想抽 <em>朝比奈まふゆ</em> 的 100 抽</s>。这已经是我第二次丢失 pjsk 账号了。</p><div style="text-align:center;"><img alt="有人丢了引き継ぎ 我不说是谁" src="'+m+'" width="40%" height="40%"></div><p>本人于 20230715 退坑 pjsk。</p><hr class="footnotes-sep">',7),le